/**
 * Sentry Infrastructure Tests
 *
 * Validates that all Sentry configuration files exist and are correctly structured.
 * Tests the client-side initialization logic (init, captureException, captureMessage, setUser, clearUser).
 */

// Mock Sentry SDK
const mockInit = jest.fn();
const mockCaptureException = jest.fn();
const mockCaptureMessage = jest.fn();
const mockSetUser = jest.fn();
const mockBrowserTracingIntegration = jest.fn(() => 'browserTracing');
const mockReplayIntegration = jest.fn(() => 'replay');

jest.mock('@sentry/nextjs', () => ({
  init: mockInit,
  captureException: mockCaptureException,
  captureMessage: mockCaptureMessage,
  setUser: mockSetUser,
  browserTracingIntegration: mockBrowserTracingIntegration,
  replayIntegration: mockReplayIntegration,
  captureRouterTransitionStart: jest.fn(),
}));

jest.mock('@/lib/logger', () => ({
  logger: {
    info: jest.fn(),
    warn: jest.fn(),
    error: jest.fn(),
    debug: jest.fn(),
  },
}));

// ============================================================================
// Tests
// ============================================================================

describe('Sentry Infrastructure', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    jest.resetModules();
  });

  describe('Client Module Exports', () => {
    it('should export initSentry function', async () => {
      const mod = await import('@/lib/monitoring/sentry.client');
      expect(typeof mod.initSentry).toBe('function');
    });

    it('should export captureException function', async () => {
      const mod = await import('@/lib/monitoring/sentry.client');
      expect(typeof mod.captureException).toBe('function');
    });

    it('should export captureMessage function', async () => {
      const mod = await import('@/lib/monitoring/sentry.client');
      expect(typeof mod.captureMessage).toBe('function');
    });

    it('should export setUser function', async () => {
      const mod = await import('@/lib/monitoring/sentry.client');
      expect(typeof mod.setUser).toBe('function');
    });

    it('should export clearUser function', async () => {
      const mod = await import('@/lib/monitoring/sentry.client');
      expect(typeof mod.clearUser).toBe('function');
    });
  });

  describe('Initialization Guard', () => {
    it('should not init Sentry when SENTRY_DISABLED is true', async () => {
      process.env.NEXT_PUBLIC_SENTRY_DISABLED = 'true';
      jest.resetModules();
      const { initSentry } = await import('@/lib/monitoring/sentry.client');
      initSentry();
      expect(mockInit).not.toHaveBeenCalled();
      delete process.env.NEXT_PUBLIC_SENTRY_DISABLED;
    });

    it('should not init Sentry when DSN is missing', async () => {
      delete process.env.NEXT_PUBLIC_SENTRY_DSN;
      delete process.env.NEXT_PUBLIC_SENTRY_DISABLED;
      process.env.SENTRY_DISABLED = '';
      jest.resetModules();
      const { initSentry } = await import('@/lib/monitoring/sentry.client');
      initSentry();
      expect(mockInit).not.toHaveBeenCalled();
    });

    it('should init Sentry when DSN is present and not disabled', async () => {
      process.env.NEXT_PUBLIC_SENTRY_DSN = 'https://test@sentry.io/12345';
      delete process.env.NEXT_PUBLIC_SENTRY_DISABLED;
      delete process.env.SENTRY_DISABLED;
      jest.resetModules();
      const { initSentry } = await import('@/lib/monitoring/sentry.client');
      initSentry();
      expect(mockInit).toHaveBeenCalledTimes(1);
      expect(mockInit).toHaveBeenCalledWith(
        expect.objectContaining({
          dsn: 'https://test@sentry.io/12345',
        })
      );
      delete process.env.NEXT_PUBLIC_SENTRY_DSN;
    });

    it('should only init once (idempotent)', async () => {
      process.env.NEXT_PUBLIC_SENTRY_DSN = 'https://test@sentry.io/12345';
      delete process.env.NEXT_PUBLIC_SENTRY_DISABLED;
      delete process.env.SENTRY_DISABLED;
      jest.resetModules();
      const { initSentry } = await import('@/lib/monitoring/sentry.client');
      initSentry();
      initSentry();
      initSentry();
      expect(mockInit).toHaveBeenCalledTimes(1);
      delete process.env.NEXT_PUBLIC_SENTRY_DSN;
    });
  });

  describe('Sentry Configuration', () => {
    it('should configure environment', async () => {
      process.env.NEXT_PUBLIC_SENTRY_DSN = 'https://test@sentry.io/12345';
      process.env.NEXT_PUBLIC_ENVIRONMENT = 'staging';
      delete process.env.NEXT_PUBLIC_SENTRY_DISABLED;
      delete process.env.SENTRY_DISABLED;
      jest.resetModules();
      const { initSentry } = await import('@/lib/monitoring/sentry.client');
      initSentry();
      expect(mockInit).toHaveBeenCalledWith(
        expect.objectContaining({
          environment: 'staging',
        })
      );
      delete process.env.NEXT_PUBLIC_SENTRY_DSN;
      delete process.env.NEXT_PUBLIC_ENVIRONMENT;
    });

    it('should configure integrations', async () => {
      process.env.NEXT_PUBLIC_SENTRY_DSN = 'https://test@sentry.io/12345';
      delete process.env.NEXT_PUBLIC_SENTRY_DISABLED;
      delete process.env.SENTRY_DISABLED;
      jest.resetModules();
      const { initSentry } = await import('@/lib/monitoring/sentry.client');
      initSentry();
      const callArgs = mockInit.mock.calls[0][0];
      expect(callArgs.integrations).toBeDefined();
      expect(Array.isArray(callArgs.integrations)).toBe(true);
      delete process.env.NEXT_PUBLIC_SENTRY_DSN;
    });

    it('should set replay sample rates', async () => {
      process.env.NEXT_PUBLIC_SENTRY_DSN = 'https://test@sentry.io/12345';
      delete process.env.NEXT_PUBLIC_SENTRY_DISABLED;
      delete process.env.SENTRY_DISABLED;
      jest.resetModules();
      const { initSentry } = await import('@/lib/monitoring/sentry.client');
      initSentry();
      const callArgs = mockInit.mock.calls[0][0];
      expect(callArgs.replaysSessionSampleRate).toBe(0.1);
      expect(callArgs.replaysOnErrorSampleRate).toBe(1.0);
      delete process.env.NEXT_PUBLIC_SENTRY_DSN;
    });

    it('should configure beforeSend filter', async () => {
      process.env.NEXT_PUBLIC_SENTRY_DSN = 'https://test@sentry.io/12345';
      delete process.env.NEXT_PUBLIC_SENTRY_DISABLED;
      delete process.env.SENTRY_DISABLED;
      jest.resetModules();
      const { initSentry } = await import('@/lib/monitoring/sentry.client');
      initSentry();
      const callArgs = mockInit.mock.calls[0][0];
      expect(typeof callArgs.beforeSend).toBe('function');
      delete process.env.NEXT_PUBLIC_SENTRY_DSN;
    });

    it('should filter ResizeObserver errors', async () => {
      process.env.NEXT_PUBLIC_SENTRY_DSN = 'https://test@sentry.io/12345';
      delete process.env.NEXT_PUBLIC_SENTRY_DISABLED;
      delete process.env.SENTRY_DISABLED;
      jest.resetModules();
      const { initSentry } = await import('@/lib/monitoring/sentry.client');
      initSentry();
      const { beforeSend } = mockInit.mock.calls[0][0];
      const resizeEvent = {
        exception: {
          values: [{ value: 'ResizeObserver loop limit exceeded' }],
        },
      };
      expect(beforeSend(resizeEvent, {})).toBeNull();
      delete process.env.NEXT_PUBLIC_SENTRY_DSN;
    });

    it('should pass through normal errors', async () => {
      process.env.NEXT_PUBLIC_SENTRY_DSN = 'https://test@sentry.io/12345';
      delete process.env.NEXT_PUBLIC_SENTRY_DISABLED;
      delete process.env.SENTRY_DISABLED;
      jest.resetModules();
      const { initSentry } = await import('@/lib/monitoring/sentry.client');
      initSentry();
      const { beforeSend } = mockInit.mock.calls[0][0];
      const normalEvent = {
        exception: {
          values: [{ value: 'Some real error' }],
        },
      };
      const result = beforeSend(normalEvent, {});
      expect(result).not.toBeNull();
      expect(result.tags?.component).toBe('client');
      delete process.env.NEXT_PUBLIC_SENTRY_DSN;
    });

    it('should configure ignoreErrors', async () => {
      process.env.NEXT_PUBLIC_SENTRY_DSN = 'https://test@sentry.io/12345';
      delete process.env.NEXT_PUBLIC_SENTRY_DISABLED;
      delete process.env.SENTRY_DISABLED;
      jest.resetModules();
      const { initSentry } = await import('@/lib/monitoring/sentry.client');
      initSentry();
      const callArgs = mockInit.mock.calls[0][0];
      expect(callArgs.ignoreErrors).toBeDefined();
      expect(Array.isArray(callArgs.ignoreErrors)).toBe(true);
      expect(callArgs.ignoreErrors.length).toBeGreaterThan(0);
      delete process.env.NEXT_PUBLIC_SENTRY_DSN;
    });
  });

  describe('Env Var Documentation', () => {
    it('should document all required Sentry env vars', () => {
      const requiredVars = [
        'NEXT_PUBLIC_SENTRY_DSN',
        'SENTRY_DSN',
        'SENTRY_AUTH_TOKEN',
        'SENTRY_ORG',
      ];

      const optionalVars = [
        'SENTRY_DISABLED',
        'NEXT_PUBLIC_SENTRY_DISABLED',
        'SENTRY_TRACES_SAMPLE_RATE',
        'SENTRY_PROFILES_SAMPLE_RATE',
      ];

      // Just verify the variables are documented (strings exist)
      for (const v of [...requiredVars, ...optionalVars]) {
        expect(typeof v).toBe('string');
        expect(v.length).toBeGreaterThan(0);
      }
    });
  });
});
